def validate_email_input(email: str) -> str:
    """Validate and normalize email address."""
    validated = validate_email(email, check_deliverability=False)
    return validated.normalized


def require_json(f):
    """Decorator to ensure request has JSON content type."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if not request.is_json:
            return jsonify({"error": "Content-Type must be application/json"}), 415
        return f(*args, **kwargs)
    return decorated


@app.route("/api/password-reset/request", methods=["POST"])
@require_json
def request_password_reset():
    """
    Request a password reset link.
    Always returns a generic success message to prevent email enumeration.
    """
    generic_response = {
        "message": "If an account with that email exists, a password reset link has been sent."
    }

    data = request.get_json(silent=True)
    if not data or "email" not in data:
        return jsonify({"error": "Email is required."}), 400

    raw_email = data.get("email", "").strip()

    # Validate email format
    try:
        email = validate_email_input(raw_email)
    except EmailNotValidError:
        # Return generic response to prevent enumeration
        return jsonify(generic_response), 200

    conn = get_db()
    try:
        # Check if user exists (but always return generic response)
        cursor = conn.execute(
            "SELECT id, email FROM users WHERE email = ?",
            (email,)
        )
        user = cursor.fetchone()

        if user is None:
            # User doesn't exist, but return generic response
            return jsonify(generic_response), 200

        # Rate limiting check
        if is_rate_limited(conn, email):
            # Still return generic response to prevent enumeration
            # but don't actually send an email or create a token
            app.logger.warning(f"Rate limit exceeded for password reset requests")
            return jsonify(generic_response), 200

        # Invalidate any existing tokens for this user
        invalidate_existing_tokens(conn, email)

        # Generate secure token
        raw_token = generate_secure_token()
        token_hash = hash_token(raw_token)

        expires_at = (
            datetime.now(timezone.utc) + timedelta(hours=TOKEN_EXPIRY_HOURS)
        ).isoformat()

        # Store hashed token in database
        conn.execute(
            """
            INSERT INTO password_reset_tokens (email, token_hash, expires_at)
            VALUES (?, ?, ?)
            """,
            (email, token_hash, expires_at)
        )
        conn.commit()

        # Build reset link
        reset_link = f"{BASE_URL}/reset-password?token={raw_token}&email={email}"

        # Send email (async in production)
        send_reset_email(email, reset_link)

    finally:
        conn.close()

    return jsonify(generic_response), 200


@app.route("/api/password-reset/validate", methods=["POST"])
@require_json
def validate_reset_token():
    """
    Validate a password reset token.
    Used by the frontend to check if a token is valid before showing the reset form.
    """
    data = request.get_json(silent=True)
    if not data or "token" not in data or "email" not in data:
        return jsonify({"error": "Token and email are required."}), 400

    raw_token = data.get("token", "").strip()
    raw_email = data.get("email", "").strip()

    if not raw_token or not raw_email:
        return jsonify({"error": "Token and email are required."}), 400

    try:
        email = validate_email_input(raw_email)
    except EmailNotValidError:
        return jsonify({"error": "Invalid request."}), 400

    token_hash = hash_token(raw_token)
    now = datetime.now(timezone.utc).isoformat()

    conn = get_db()
    try:
        cursor = conn.execute(
            """
            SELECT id FROM password_reset_tokens
            WHERE token_hash = ? AND email = ? AND used = 0 AND expires_at > ?
            """,
            (token_hash, email, now)
        )
        token_record = cursor.fetchone()
    finally:
        conn.close()

    if token_record is None:
        return jsonify({"valid": False, "error": "Invalid or expired token."}), 400

    return jsonify({"valid": True}), 200


@app.route("/api/password-reset/confirm", methods=["POST"])
@require_json
def confirm_password_reset():
    """
    Confirm password reset with token and new password.
    """
    data = request.get_json(silent=True)
    if not data:
        return jsonify({"error": "Invalid request."}), 400

    raw_token = data.get("token", "").strip()
    raw_email = data.get("email", "").strip()
    new_password = data.get("new_password", "")

    if not raw_token or not raw_email or not new_password:
        return jsonify({"error": "Token, email, and new password are required."}), 400

    # Validate email
    try:
        email = validate_email_input(raw_email)
    except EmailNotValidError:
        return jsonify({"error": "Invalid request."}), 400

    # Validate password strength
    if len(new_password) < 8:
        return jsonify({"error": "Password must be at least 8 characters long."}), 400

    if len(new_password) > 128:
        return jsonify({"error": "Password must not exceed 128 characters."}), 400

    token_hash = hash_token(raw_token)
    now = datetime.now(timezone.utc).isoformat()

    conn = get_db()
    try:
        # Find valid token
        cursor = conn.execute(
            """
            SELECT id, email FROM password_reset_tokens
            WHERE token_hash = ? AND email = ? AND used = 0 AND expires_at > ?
            """,
            (token_hash, email, now)
        )
        token_record = cursor.fetchone()

        if token_record is None:
            return jsonify({"error": "Invalid or expired token."}), 400

        # Hash the new password using hashlib (for MVP; use bcrypt/argon2 in production)
        # Using a proper password hashing approach
        import hashlib as _hashlib
        salt = secrets.token_hex(32)
        password_hash = _hashlib.pbkdf2_hmac(
            "sha256",
            new_password.encode("utf-8"),
            salt.encode("utf-8"),
            iterations=600000
        ).hex()
        stored_hash = f"pbkdf2:sha256:600000${salt}${password_hash}"

        # Update user password
        conn.execute(
            "UPDATE users SET password_hash = ? WHERE email = ?",
            (stored_hash, email)
        )

        # Mark token as used
        conn.execute(
            "UPDATE password_reset_tokens SET used = 1 WHERE id = ?",
            (token_record["id"],)
        )

        # Invalidate all other tokens for this user
        invalidate_existing_tokens(conn, email)

        conn.commit()

    finally:
        conn.close()

    return jsonify({"message": "Password has been reset successfully."}), 200


